import { parseEther, parseUnits, encodeAbiParameters, parseAbiParameters, formatUnits, createPublicClient, http, fallback } from 'viem'
import { mainnet } from 'viem/chains'
import type { WalletClient, PublicClient } from 'viem'
import { ROUTERS, WETH } from './wagmi'

// ── Payment constants ─────────────────────────────────────────────────────────
export const TREASURY     = '0xA7d617117887b3cAf2C93B07ceD3081Ee9F8F63a' as `0x${string}` // REPLACE with your wallet
export const BLIN_ADDRESS = '0xaEFB54306240502c5421Be478fa16aACfA9698A2' as `0x${string}`
export const BLIN_CHAIN_ID = 1 // $BLIN is on Ethereum mainnet

// Dedicated Ethereum mainnet client for all BLIN reads
// This is chain-agnostic — it always hits mainnet regardless of the user's connected chain
const ethMainnetClient = createPublicClient({
  chain: mainnet,
  transport: fallback([
    http('https://eth.llamarpc.com'),
    http('https://rpc.ankr.com/eth'),
    http('https://1rpc.io/eth'),
    http('https://ethereum.publicnode.com'),
  ]),
})

export const TIER_PRICES = {
  starter: { blin: parseUnits('50000',  18), native: parseEther('0.05'),  label: '$49'  },
  pro:     { blin: parseUnits('150000', 18), native: parseEther('0.15'),  label: '$149' },
  elite:   { blin: parseUnits('400000', 18), native: parseEther('0.40'),  label: '$399' },
}

// ERC-20 ABI (minimal)
export const ERC20_ABI = [
  {
    name: 'transfer',
    type: 'function',
    stateMutability: 'nonpayable',
    inputs:  [{ name: 'to', type: 'address' }, { name: 'amount', type: 'uint256' }],
    outputs: [{ type: 'bool' }],
  },
  {
    name: 'balanceOf',
    type: 'function',
    stateMutability: 'view',
    inputs:  [{ name: 'account', type: 'address' }],
    outputs: [{ type: 'uint256' }],
  },
] as const

// ── Pay with BLIN ─────────────────────────────────────────────────────────────
// $BLIN lives on Ethereum mainnet. We:
//   1. Read balance via a dedicated mainnet public client (not the user's active chain)
//   2. Ask the wallet to switch to mainnet before sending the transfer
//   3. Wait for receipt on mainnet
export async function payWithBLIN(
  tier: string,
  walletClient: WalletClient,
  _publicClient: PublicClient, // kept for API compat, but we use ethMainnetClient for reads
  onStatus: (s: string) => void,
  overrideBlinAmount?: bigint,  // explicit amount from Supabase dynamic pricing
): Promise<string> {
  const fallback = TIER_PRICES[tier as keyof typeof TIER_PRICES]
  const blinAmount = overrideBlinAmount ?? fallback?.blin
  if (!blinAmount) throw new Error('Unknown tier')
  // Build a price-like object so the rest of the function stays unchanged
  const price = { blin: blinAmount }

  const [account] = await walletClient.getAddresses()

  // 1. Check balance on Ethereum mainnet directly
  onStatus('Checking BLIN balance on Ethereum mainnet…')
  let bal: bigint
  try {
    bal = await ethMainnetClient.readContract({
      address: BLIN_ADDRESS,
      abi: ERC20_ABI,
      functionName: 'balanceOf',
      args: [account],
    }) as bigint
  } catch (e: any) {
    throw new Error(`Failed to read BLIN balance. Make sure you are using an Ethereum-compatible wallet.\n${e.message}`)
  }

  if (bal < price.blin) {
    throw new Error(
      `Insufficient BLIN balance. You have ${formatUnits(bal, 18)} BLIN but need ${formatUnits(price.blin, 18)} BLIN.\n` +
      `$BLIN contract: ${BLIN_ADDRESS} (Ethereum mainnet)`
    )
  }

  // 2. Switch wallet to Ethereum mainnet for the transfer
  onStatus('Switching wallet to Ethereum mainnet for BLIN transfer…')
  try {
    await walletClient.switchChain({ id: mainnet.id })
  } catch (e: any) {
    // Some wallets throw if already on the right chain — that's fine
    if (!e.message?.includes('already') && !e.message?.includes('same')) {
      throw new Error(`Could not switch to Ethereum mainnet: ${e.message}`)
    }
  }

  // 3. Send BLIN transfer on mainnet
  onStatus('Sending BLIN payment…')
  const hash = await walletClient.writeContract({
    address: BLIN_ADDRESS,
    abi: ERC20_ABI,
    functionName: 'transfer',
    args: [TREASURY, price.blin],
    account,
    chain: mainnet,
  })

  // 4. Wait for confirmation on mainnet
  onStatus('Waiting for confirmation on Ethereum mainnet…')
  await ethMainnetClient.waitForTransactionReceipt({ hash })
  return hash
}

// ── Pay with native (ETH/BNB on user's connected chain) ───────────────────────
export async function payWithNative(
  tier: string,
  walletClient: WalletClient,
  publicClient: PublicClient,
  onStatus: (s: string) => void,
  overrideNativeAmount?: bigint,  // explicit amount from Supabase dynamic pricing
): Promise<string> {
  const fallback = TIER_PRICES[tier as keyof typeof TIER_PRICES]
  const nativeAmount = overrideNativeAmount ?? fallback?.native
  if (!nativeAmount) throw new Error('Unknown tier')
  const [account] = await walletClient.getAddresses()

  onStatus('Sending payment…')
  const hash = await walletClient.sendTransaction({
    to: TREASURY,
    value: nativeAmount,
    account,
    chain: walletClient.chain!,
  })

  onStatus('Waiting for confirmation…')
  await publicClient.waitForTransactionReceipt({ hash })
  return hash
}

// ── Deploy FatTokenV6 ─────────────────────────────────────────────────────────
// Paste compiled bytecode here from Remix (Solidity 0.8.4, 200 runs, FatTokenV6.sol)
export const FAT_BYTECODE = "" as `0x${string}`

export type DeployArgs = {
  name: string; symbol: string; decimals: number; totalSupply: string
  fundAddress: `0x${string}`; receiveAddress: `0x${string}`; rewardToken: `0x${string}`
  buyFund: number; buyLP: number; buyReward: number; buyBurn: number
  sellFund: number; sellLP: number; sellReward: number; sellBurn: number
  maxBuyAmount: string; maxWalletAmount: string
  enableChangeTax: boolean; enableKillBlock: boolean; enableSwapLimit: boolean
  enableWalletLimit: boolean; enableOffTrade: boolean
  enableKillBatchBots: boolean; enableTransferFee: boolean; antiSYNC: boolean
  currencyIsEth: boolean; kb: number; killBatchBlockNumber: number; airdropNumbs: number
  chainId: number
}

export async function deployFatToken(
  args: DeployArgs,
  walletClient: WalletClient,
  publicClient: PublicClient,
  onStatus: (s: string) => void
): Promise<{ contractAddress: string; txHash: string; constructorArgs: string }> {
  if (!FAT_BYTECODE) {
    throw new Error(
      'Bytecode not loaded. Paste compiled FatTokenV6 bytecode into src/lib/contracts.ts → FAT_BYTECODE.'
    )
  }

  const dec0 = 10n ** BigInt(args.decimals)
  const router = ROUTERS[args.chainId] ?? ROUTERS[56]
  const [account] = await walletClient.getAddresses()

  const stringParams  = [args.name, args.symbol]
  const addressParams = [
    args.fundAddress,
    '0x0000000000000000000000000000000000000000' as `0x${string}`,
    router,
    args.receiveAddress,
    (args.rewardToken && args.rewardToken.length > 10 ? args.rewardToken : WETH[args.chainId] ?? WETH[56]) as `0x${string}`,
  ]
  const numberParams  = [
    BigInt(args.decimals),
    BigInt(args.totalSupply) * dec0,
    BigInt(args.maxBuyAmount) * dec0,
    0n,
    BigInt(args.maxWalletAmount) * dec0,
    BigInt(args.buyFund), BigInt(args.buyLP), BigInt(args.buyReward), BigInt(args.buyBurn),
    BigInt(args.sellFund), BigInt(args.sellLP), BigInt(args.sellReward), BigInt(args.sellBurn),
    BigInt(args.killBatchBlockNumber), BigInt(args.kb), BigInt(args.airdropNumbs),
  ]
  const boolParams = [
    args.enableOffTrade, args.enableKillBlock, false, // boolParams[2] ignored in V6 (blacklist removed)
    args.enableSwapLimit, args.enableWalletLimit, args.enableChangeTax,
    args.currencyIsEth, args.enableKillBatchBots, args.enableTransferFee, args.antiSYNC,
  ]

  onStatus('Encoding constructor args…')
  const encodedArgs = encodeAbiParameters(
    parseAbiParameters('string[], address[], uint256[], bool[]'),
    [stringParams, addressParams as readonly `0x${string}`[], numberParams, boolParams]
  )

  const deployData = (FAT_BYTECODE + encodedArgs.slice(2)) as `0x${string}`

  onStatus('Estimating gas…')
  const gasEstimate = await publicClient.estimateGas({ account, data: deployData })

  onStatus(`Gas: ~${gasEstimate.toLocaleString()} units. Confirm in wallet…`)
  const hash = await walletClient.sendTransaction({
    account,
    data: deployData,
    gas: gasEstimate * 120n / 100n, // 20% buffer
    chain: walletClient.chain!,
  })

  onStatus('Waiting for confirmation…')
  const receipt = await publicClient.waitForTransactionReceipt({ hash })
  const contractAddress = receipt.contractAddress ?? '0x???'

  return { contractAddress, txHash: hash, constructorArgs: encodedArgs.slice(2) }
}

// ── Constructor param string generator ───────────────────────────────────────
export function generateParams(cfg: any, chainId: number): string {
  const router = ROUTERS[chainId] ?? ROUTERS[56]
  const dec0   = '0'.repeat(cfg.decimals)
  return `// stringParams
[0] name    = "${cfg.name || 'My Token'}"
[1] symbol  = "${cfg.symbol || 'MTK'}"

// addressParams
[0] fundAddress     = "${cfg.fundAddress || '0x...'}"
[1] currency        = "${cfg.currencyIsEth ? '(auto — WETH/WBNB)' : '0x...'}"
[2] swapRouter      = "${router}"
[3] receiveAddress  = "${cfg.receiveAddress || '0x...'}"
[4] rewardToken     = "${cfg.rewardToken || '0x...'}"

// numberParams
[0]  decimals              = ${cfg.decimals}
[1]  totalSupply           = ${cfg.totalSupply}${dec0}
[2]  maxBuyAmount          = ${cfg.maxBuyAmount}${dec0}
[3]  (unused)              = 0
[4]  maxWalletAmount       = ${cfg.maxWalletAmount}${dec0}
[5]  _buyFundFee           = ${cfg.buyFund}
[6]  _buyLPFee             = ${cfg.buyLP}
[7]  _buyRewardFee         = ${cfg.buyReward}
[8]  buy_burnFee           = ${cfg.buyBurn}
[9]  _sellFundFee          = ${cfg.sellFund}
[10] _sellLPFee            = ${cfg.sellLP}
[11] _sellRewardFee        = ${cfg.sellReward}
[12] sell_burnFee          = ${cfg.sellBurn}
[13] killBatchBlockNumber  = ${cfg.killBatchBlockNumber}
[14] kb                    = ${cfg.kb}
[15] airdropNumbs          = ${cfg.airdropNumbs}

// boolParams
[0] enableOffTrade         = ${cfg.enableOffTrade}
[1] enableKillBlock        = ${cfg.enableKillBlock}
[2] (blacklist removed V6) = false
[3] enableSwapLimit        = ${cfg.enableSwapLimit}
[4] enableWalletLimit      = ${cfg.enableWalletLimit}
[5] enableChangeTax        = ${cfg.enableChangeTax}
[6] currencyIsEth          = ${cfg.currencyIsEth}
[7] enableKillBatchBots    = ${cfg.enableKillBatchBots}
[8] enableTransferFee      = ${cfg.enableTransferFee}
[9] antiSYNC               = ${cfg.antiSYNC}`
}
